<script setup lang="ts">
import { shallowRef, watch } from 'vue'

import QVoiceBase from './base/QVoiceBase.vue'
import { useVoiceProgress, formatDuration } from '@pkg/composables/useVoiceProgress'
import type { MessageProps } from '@pkg/types/message'
import { messagePropsDefaults } from '@pkg/types/message'

const props = withDefaults(
  defineProps<MessageProps & {
    src: string
    text?: string
    volume?: number
  }>(),
  {
    ...messagePropsDefaults,
    text: '[呃，什么都没有听到]',
    volume: 1.0
  }
)

const {
  progressItemsRef,
  processLinePos,
  formatedDuration,
  playEnded,
  playPaused,
  onPlaybackStart,
  pause: pauseProgress,
  resume: resumeProgress,
  reset: resetProgress
} = useVoiceProgress()

const audio = shallowRef<HTMLAudioElement>()
const duration = shallowRef(0)
const processHeightRefs = shallowRef<number[]>([])

function getLineCount(num: number) {
  num = num / 1.2
  return Array.from({ length: num >= 25 ? 25 : num < 5 ? 5 : num }, () => getRndInteger(30, 60))
}

function getRndInteger(min: number, max: number) {
  return Math.floor(Math.random() * (max - min + 1)) + min
}

async function loadAudio() {
  if (!audio.value) return
  duration.value = Math.round(audio.value.duration)

  formatedDuration.value = formatDuration(duration.value)
  processHeightRefs.value = getLineCount(duration.value)
}

function play() {
  if (!(audio.value && progressItemsRef.value)) return

  if (playEnded.value) {
    audio.value.play()
    onPlaybackStart(
      [...progressItemsRef.value.children] as HTMLDivElement[],
      duration.value
    )
  } else {
    if (audio.value.paused) {
      audio.value.play()
      resumeProgress()
    } else {
      audio.value.pause()
      pauseProgress()
    }
  }
}

watch(
  () => props.volume,
  volume => {
    if (audio.value === undefined) return
    audio.value.volume = volume
  }
)
</script>

<template>
  <q-voice-base
    :self="self"
    :name="name"
    :avatar="avatar"
    :tag="tag"
    :tag-color="tagColor"
    :is-bot="isBot"
    :src="src"
    :play="play"
    :play-paused="playPaused"
    :formated-duration="formatedDuration"
    :text="text"
  >
    <audio ref="audio" :src="src" @ended="resetProgress" @loadedmetadata="loadAudio"></audio>
    <div
      ref="progressItemsRef"
      class="ptt-element__progress"
      style="--process-item-color: var(--qq-text_primary)"
    >
      <div
        v-if="!playEnded"
        class="ptt-element__progress-tag"
        :style="{ left: `calc(${processLinePos}% - 1px)` }"
      ></div>
      <div
        v-for="(height, index) in processHeightRefs"
        :key="index"
        class="ptt-element__progress-item"
        :style="{ height: `${height}%` }"
      ></div>
    </div>
  </q-voice-base>
</template>
