import { shallowRef } from 'vue'
import { useIntervalFn } from '@vueuse/core'

/** Format seconds to m'ss" or ss" */
export function formatDuration(duration: number): string {
  const m = Math.floor(duration / 60)
  const s = Math.round(duration % 60)
  return m > 0 ? `${m}'${s}"` : `${s}"`
}

/**
 * Shared voice playback progress controller.
 * Manages progress bar animation, play/pause state, and duration formatting.
 */
export function useVoiceProgress() {
  const progressItemsRef = shallowRef<HTMLDivElement>()
  const processLinePos = shallowRef(0)
  const playEnded = shallowRef(true)
  const playPaused = shallowRef(true)
  const formatedDuration = shallowRef('')

  let pauseFn: (() => void) | undefined
  let resumeFn: (() => void) | undefined

  function start(progressItems: HTMLElement[], duration: number) {
    progressItemsRef.value?.style.setProperty(
      '--process-item-color',
      'var(--qq-text-secondary-01)'
    )

    let i = 0
    const barInterval = (Math.floor(duration) / progressItems.length) * 1000
    const lineInterval = (Math.floor(duration) / 100) * 1000

    const { pause: pauseBar, resume: resumeBar } = useIntervalFn(
      () => {
        if (playEnded.value) {
          pauseBar()
          i = 0
          progressItems.forEach(item => item.style.removeProperty('--process-item-color'))
          progressItemsRef.value?.style.setProperty(
            '--process-item-color',
            'var(--qq-text_primary)'
          )
        }
        progressItems[i]?.style.setProperty('--process-item-color', 'var(--qq-text_primary)')
        i++
      },
      barInterval,
      { immediate: true }
    )

    const { pause: pauseLine, resume: resumeLine } = useIntervalFn(
      () => {
        if (playEnded.value) {
          pauseLine()
          processLinePos.value = 0
        }
        processLinePos.value++
      },
      lineInterval,
      { immediate: true }
    )

    pauseFn = () => { pauseBar(); pauseLine() }
    resumeFn = () => { resumeBar(); resumeLine() }
  }

  function onPlaybackStart(progressItems: HTMLElement[], duration: number) {
    start(progressItems, duration)
    playEnded.value = false
    playPaused.value = false
  }

  function pause() {
    pauseFn?.()
    playPaused.value = true
  }

  function resume() {
    resumeFn?.()
    playPaused.value = false
  }

  function reset() {
    playEnded.value = true
    playPaused.value = true
  }

  return {
    progressItemsRef,
    processLinePos,
    playEnded,
    playPaused,
    formatedDuration,
    /** Call when starting playback from beginning */
    onPlaybackStart,
    /** Call to pause (e.g. audioCtx.suspend / audio.pause) */
    pause,
    /** Call to resume (e.g. audioCtx.resume / audio.play) */
    resume,
    /** Call on playback ended */
    reset
  }
}
